double prev = 0; int ups = 0, downs = 0;
for (int i = 0; i < 10; i++)
{
    double curr = Plc.ReadHoldingRegister(100) / 10.0;
    string trend = curr > prev ? "↑" : curr < prev ? "↓" : "→";
    if (curr > prev) ups++; else if (curr < prev) downs++;
    Print($"[{i}] {curr:F1}°C {trend}");
    prev = curr;
    Plc.WriteHoldingRegister(100, (ushort)((curr + 0.5) * 10));
}
Print($"上升{ups}次, 下降{downs}次");
Print("趋势分析完成");
